--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelMail:OnModelInit()
	self:ParseConfig()

	self:ModelNetMsgRecv(LProtoIds.MailListResp,function(...)
		self:OnMailListResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.MailReaderResp,function(...)
		self:OnMailReaderResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.MailReceiveResp,function(...)
		self:OnMailReceiveResp(...)
	end)
	self:ModelNetMsgRecv(LProtoIds.MailRemoveResp,function(...)
		self:OnMailRemoveResp(...)
	end)
end

--在协议数据处理完之后需要调用finish
function ModelMail:OnModelRequest()
	self._readingMailIds={} --待确认打开的邮件
	self:ModelFinish()
end

--------------------------------------------
---req
function ModelMail:MailListReq()
	local pb = LProtoHelper.CreateProto(LProtoIds.MailListReq)
	SendMessage(pb,LProtoIds.MailListReq)
end

function ModelMail:MailReaderReq(mailId)
	local pb = LProtoHelper.CreateProto(LProtoIds.MailReaderReq)
	pb.mailId = mailId

	SendMessage(pb,LProtoIds.MailReaderReq)
	table.insert(self._readingMailIds,mailId)
end

function ModelMail:MailReceiveReq(receiveType,mailId)
	if receiveType ==2 then
		if not self:CheckCanGetAll() then
			GF.ShowMessage(ccClientText(11210))
			return
		end
	end
	local pb = LProtoHelper.CreateProto(LProtoIds.MailReceiveReq)
	pb.receiveType = receiveType
	if receiveType ==1 then
		pb.mailId = mailId
	end
	SendMessage(pb,LProtoIds.MailReceiveReq)
end

function ModelMail:MailRemoveReq(removeType,mailId)
	local pb = LProtoHelper.CreateProto(LProtoIds.MailRemoveReq)
	pb.removeType = removeType
	if removeType ==1 then
		pb.mailId = mailId
	end
	SendMessage(pb,LProtoIds.MailRemoveReq)
end



--------------------------------------------
---resp

function ModelMail:OnMailListResp(pb,ret)
	self._mailList = {}
	local mailTotalNum = 0
	local specialTotal = 0
	local mailUnreadNum = 0
	local specialUnread = 0
	for k,v in ipairs(pb.mailContent) do

		--地区屏蔽
		local refId = v.refId
		if refId > 0 and gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.MAIL,refId) then
		else
			local mail = StructMail:New()
			mail:CreateByPb(v)
			self._mailList[mail._mailId] =mail
		end

	end

	for k,v in pairs(self._mailList) do

		if v._mailType == 1 or v._mailType == 3 then
			mailTotalNum = mailTotalNum+ 1
			if not v._read then
				mailUnreadNum = mailUnreadNum + 1
			end
		else
			specialTotal = specialTotal+ 1
			if not v._read then
				specialUnread = specialUnread + 1
			end
		end
	end

	self:SetMailTotalNum(StructMail.NORMAL,mailTotalNum)
	self:SetMailTotalNum(StructMail.SPECIAL,specialTotal)

	self:SetMailUnreadNum(StructMail.NORMAL,mailUnreadNum)
	self:SetMailUnreadNum(StructMail.SPECIAL,specialUnread)
end



-- 返回表示打开成功
function ModelMail:OnMailReaderResp(pb,ret)
	for k,v in ipairs(self._readingMailIds) do
		local mailId = v
		local mail = self._mailList[mailId]
		if mail then
			mail._read = true
			local unreadNum = self:GetUnreadMailNum(mail._mailType)
			unreadNum = unreadNum -1
			self:SetMailUnreadNum(mail._mailType,unreadNum)
		end
	end
	self._readingMailIds= {}
end

function ModelMail:OnMailReceiveResp(pb,ret)
	for k,v in ipairs(pb.mailId) do
		local mail = self._mailList[v]
		if mail then
			if not mail._read then
				local unreadNum = self:GetUnreadMailNum(mail._mailType)
				unreadNum = unreadNum -1
				self:SetMailUnreadNum(mail._mailType,unreadNum)
			end
			mail._read = true
			mail._fetch = true
			if(mail._mailType == 3)then
				self._mailList[v] = nil
				local total = self:GetTotalMailNum(1)
				total=total -1
				self:SetMailTotalNum(1,total)
				local unreadNum = self:GetUnreadMailNum(1)
				unreadNum = unreadNum -1
				self:SetMailUnreadNum(1,unreadNum)
			end
		end
	end


end

function ModelMail:OnMailRemoveResp(pb,ret)
	for k,v in ipairs(pb.mailIds) do
		local mail = self._mailList[v]
		if mail then
			self._mailList[v] =nil

			local total = self:GetTotalMailNum(mail._mailType)
			total=total -1
			self:SetMailTotalNum(mail._mailType,total)

			if not mail._read then
				local unreadNum = self:GetUnreadMailNum(mail._mailType)
				unreadNum = unreadNum -1
				self:SetMailUnreadNum(mail._mailType,unreadNum)
			end
		end
	end

end


