function ModelMail:GetSortedMailList(type) --	自上而下显示最新接收的邮件   	已读状态的邮件，显示在未读状态的邮件后面

	local t = {}
	for k,v in pairs(self._mailList) do
		if v._mailType == type or (v._mailType == 3 and v._read == false and type == 1) then
			table.insert(t,v)
		end
	end

	local compare = function(a,b)
		local readA = a._read and 0 or 1
		local readB = b._read and 0 or 1
		local topA = a._refId ~= 99 and 0 or 1
		local topB = b._refId ~= 99 and 0 or 1
		if(topA ~= topB)then
			return topA>topB
		end
		if readA ~= readB then
			return readA>readB
		end
		return a._receiveTime>b._receiveTime
	end
	table.sort(t,compare)
	return  t
end

function ModelMail:GetTotalMailNum(type)
	if not self._totalMap then
		return 0
	end
	return self._totalMap[type] or 0
end

function ModelMail:GetUnreadMailNum(type)
	if not self._unreadMap then
		return 0
	end
	return self._unreadMap[type] or 0
end

function ModelMail:SetMailTotalNum(type,cnt)
	if not self._totalMap then
		self._totalMap = {}
	end
	self._totalMap[type] = cnt
end

function ModelMail:SetMailUnreadNum(type,cnt)
	if not self._unreadMap then
		self._unreadMap = {}
	end
	self._unreadMap[type] = cnt
end

function ModelMail:GetMailCfg(refId)
	return GameTable.GameMailRef[refId]
end

function ModelMail:GetMailByMailId(mailId)
	return self._mailList[mailId]
end

