function ModelMail:CheckCanGetAll()
	if not self._mailList then
		return false
	end
	for k,v in pairs(self._mailList) do
		if  not table.isempty(v._attachments) and not v._fetch then
			return true
		end
	end
	return false
end

function ModelMail:DeleteMail(removeType,mailId)
	if not self._mailList then
		return
	end

	local hasUnread = false
	local unget = false
	if removeType ==2 then
		for k,v in pairs(self._mailList) do
			if v._mailType == 1 then
				if v._read then
					hasUnread= true
				end
				unget = self:CheckMailItemUnget(v)
				if unget then
					break
				end
			end
		end

		if unget then
			local wndId = 20001
			local func = function()
				self:MailRemoveReq(removeType,mailId)
			end
			gModelGeneral:OpenUIOrdinTips({refId=wndId,func = func})
			return
		end
	elseif removeType ==1 then
		local mail = self._mailList[mailId]
		if mail then
			if mail._read then
				hasUnread = true
			end
			unget = self:CheckMailItemUnget(mail)
			if unget then
				local wndId = 20001
				local func = function()
					self:MailRemoveReq(removeType,mailId)
				end
				gModelGeneral:OpenUIOrdinTips({refId=wndId,func = func})
				return
			end
		end
	end
	if hasUnread then
		self:MailRemoveReq(removeType,mailId)
	else
		GF.ShowMessage(ccClientText(11211))
	end

end

function ModelMail:CheckMailItemUnget(mail)
	if mail._read then
		if not mail._fetch and not table.isempty(mail._attachments) then
			return true
		end
	end
	return false
end

function ModelMail:GetMaxMailKeep(type)
	if type == 1 then
		return GameTable.GameMailConfigRef["mailkeepNum"]
	else
		return GameTable.GameMailConfigRef["mailkeepNumGM"]
	end
end

function ModelMail:CheckNeedShield(refId)
	return self._shieldMailList[refId] or false
end

function ModelMail:ParseConfig()
	local cfg = GameTable.GameMailConfigRef["mailShield"]
	local strs = string.split(cfg,';')
	self._shieldMailList ={}
	for k,v in ipairs(strs) do
		local id = tonumber(v)
		if id then
			self._shieldMailList[id] = true
		end
	end
end

function ModelMail:FormatShowItems(itemList)
	local dataList= {}
	for k,v in ipairs(itemList) do
		local itemId = v.itemId
		local itemNum = v.count
		local itemType = v.type
		if itemType == 2 then
			for i = 1,itemNum do
				local data = {
					itemId = itemId,
					itemType = itemType,
					itemNum = 1
				}
				table.insert(dataList,data)
			end
		else
			local data = {
				itemId = itemId,
				itemType = itemType,
				itemNum = itemNum
			}
			table.insert(dataList,data)
		end
	end
	return dataList
end

